"""
This module contains the core game logic for Checkers.
"""

class Piece:
    def __init__(self, position, color):
        self.position = position
        self.color = color
        self.is_king = False

    def move(self, new_position):
        self.position = new_position
        if self.color == "white" and new_position[1] == 7 or self.color == "black" and new_position[1] == 0:
            self.king()

    def king(self):
        self.is_king = True

class Board:
    def __init__(self):
        self.pieces = []
        self.initialize_board()

    def initialize_board(self):
        for row in range(8):
            if row % 2 == 0:
                start_col = 1
            else:
                start_col = 0
            for col in range(start_col, 8, 2):
                if row < 3:
                    self.pieces.append(Piece((row, col), "white"))
                elif row > 4:
                    self.pieces.append(Piece((row, col), "black"))

    def place_piece(self, piece, position):
        piece.position = position

class Game:
    def __init__(self):
        self.board = Board()
        self.players = ["white", "black"]
        self.current_player_index = 0
        self.game_over = False

    def get_all_pieces(self, color):
        return [piece for piece in self.board.pieces if piece.color == color]

    def parse_move(self, move):
        # Example: a2-a4
        start_col = ord(move[0]) - ord('a')
        start_row = int(move[1]) - 1
        end_col = ord(move[3]) - ord('a')
        end_row = int(move[4]) - 1
        return (start_row, start_col), (end_row, end_col)

    def is_valid_move(self, move):
        start_pos, end_pos = self.parse_move(move)
        piece = next((p for p in self.board.pieces if p.position == start_pos), None)
        if piece and piece.color == self.players[self.current_player_index]:
            # TODO: Add logic to check valid moves including capturing
            return True
        return False

    def make_move(self, move):
        start_pos, end_pos = self.parse_move(move)
        for piece in self.board.pieces:
            if piece.position == start_pos:
                piece.move(end_pos)
                break

    def check_winner(self):
        player_pieces = self.get_all_pieces(self.players[self.current_player_index])
        opponent_pieces = self.get_all_pieces(self.players[1 - self.current_player_index])
        if not player_pieces or not any(p.is_king for p in player_pieces):
            return "black" if self.players[self.current_player_index] == "white" else "white"
        elif not opponent_pieces:
            return "white" if self.players[self.current_player_index] == "black" else "black"
        return None

    def play(self):
        while not self.game_over:
            current_player = self.players[self.current_player_index]
            print(f"{current_player}'s turn. Enter move (e.g., a2-a4): ", end="")
            move = input().strip()
            if move.lower() in ["exit", "quit"]:
                break
            if self.is_valid_move(move):
                self.make_move(move)
                winner = self.check_winner()
                if winner:
                    print(f"{winner.capitalize()} wins!")
                    self.game_over = True
                elif all(p.is_king for p in self.get_all_pieces(current_player)):
                    print("Game drawn! Both players have kings.")
                    self.game_over = True
            else:
                print("Invalid move. Please try again.")

if __name__ == "__main__":
    game = Game()
    game.play()
